import{_ as a,o as t,c as s,ag as n}from"./chunks/framework.NsnsQ6zO.js";const u=JSON.parse('{"title":"RFC-001: Process State Machine Design","description":"","frontmatter":{},"headers":[],"relativePath":"rfcs/RFC-001-PROCESS-STATE-MACHINE.md","filePath":"rfcs/RFC-001-PROCESS-STATE-MACHINE.md"}'),r={name:"rfcs/RFC-001-PROCESS-STATE-MACHINE.md"};function i(o,e,d,l,c,p){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="rfc-001-process-state-machine-design" tabindex="-1">RFC-001: Process State Machine Design <a class="header-anchor" href="#rfc-001-process-state-machine-design" aria-label="Permalink to &quot;RFC-001: Process State Machine Design&quot;">​</a></h1><blockquote><p><strong>Status:</strong> accepted</p><p><strong>Author:</strong> AgentVM Core Team</p><p><strong>Created:</strong> 2026-03-26</p></blockquote><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Defines the lifecycle states and valid transitions for agent processes in AgentVM.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>Agents need a well-defined lifecycle so that frameworks and operators can reason about what state an agent is in, what operations are valid, and how to handle crashes gracefully.</p><h2 id="detailed-design" tabindex="-1">Detailed Design <a class="header-anchor" href="#detailed-design" aria-label="Permalink to &quot;Detailed Design&quot;">​</a></h2><h3 id="states" tabindex="-1">States <a class="header-anchor" href="#states" aria-label="Permalink to &quot;States&quot;">​</a></h3><table tabindex="0"><thead><tr><th>State</th><th>Description</th></tr></thead><tbody><tr><td><code>created</code></td><td>Process object exists but hasn&#39;t started</td></tr><tr><td><code>starting</code></td><td>Initialization in progress (allocating memory, loading tools)</td></tr><tr><td><code>running</code></td><td>Actively executing</td></tr><tr><td><code>paused</code></td><td>Temporarily suspended, can be resumed</td></tr><tr><td><code>terminated</code></td><td>Cleanly shut down, final state</td></tr><tr><td><code>crashed</code></td><td>Unhandled error occurred, final state</td></tr></tbody></table><h3 id="valid-transitions" tabindex="-1">Valid Transitions <a class="header-anchor" href="#valid-transitions" aria-label="Permalink to &quot;Valid Transitions&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>created    → starting     (spawn)</span></span>
<span class="line"><span>starting   → running      (automatic after init)</span></span>
<span class="line"><span>running    → paused       (pause)</span></span>
<span class="line"><span>paused     → running      (resume)</span></span>
<span class="line"><span>running    → terminated   (terminate)</span></span>
<span class="line"><span>paused     → terminated   (terminate)</span></span>
<span class="line"><span>running    → crashed      (unhandled error)</span></span>
<span class="line"><span>starting   → crashed      (init failure)</span></span></code></pre></div><p>Any transition not listed above throws an <code>InvalidStateTransitionError</code>.</p><h3 id="terminal-states" tabindex="-1">Terminal States <a class="header-anchor" href="#terminal-states" aria-label="Permalink to &quot;Terminal States&quot;">​</a></h3><p><code>terminated</code> and <code>crashed</code> are terminal. Once a process reaches either state, no further transitions are possible. To restart, spawn a new process.</p><h2 id="trade-offs" tabindex="-1">Trade-offs <a class="header-anchor" href="#trade-offs" aria-label="Permalink to &quot;Trade-offs&quot;">​</a></h2><ul><li><strong>No <code>restarting</code> state</strong>: We chose simplicity. Restart = spawn a new process. This avoids complex state management around partial restarts.</li><li><strong>No <code>stopping</code> state</strong>: Termination is immediate (via AbortController). If we need graceful shutdown in the future, we can add a <code>stopping</code> state in a backward-compatible way.</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives Considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives Considered&quot;">​</a></h2><ul><li><strong>Erlang-style supervision trees</strong>: Too complex for v0.1. Could be added in Phase 3.</li><li><strong>Allowing restart from crashed</strong>: Increases complexity. Checkpointing (Phase 3) is a better solution.</li></ul><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://www.erlang.org/doc/reference_manual/processes" target="_blank" rel="noreferrer">Erlang Process Model</a></li><li><a href="https://kubernetes.io/docs/concepts/workloads/pods/pod-lifecycle/" target="_blank" rel="noreferrer">Kubernetes Pod Lifecycle</a></li></ul>`,20)])])}const g=a(r,[["render",i]]);export{u as __pageData,g as default};
